+func TestFormatObsidianTask_ParentChildDependency(t *testing.T) {
+	issue := &types.Issue{
+		ID:        "test-1.1",
+		Title:     "Child Task",
+		Status:    types.StatusOpen,
+		Priority:  2,
+		CreatedAt: time.Now(),
